class Solution {
    public int minSwaps(String s) {
        int count = 0;
        int open = 0;
        for (char c : s.toCharArray()) {
            if (c == '[') {
                open++;
            } else {
                if (open == 0) {
                    count++;
                    open++;
                } else {
                    open--;
                }
            }
        }
        return count;
    }
}
